package ratelimit

import (
	"testing"
	"time"
)

func TestAllowWithinLimit(t *testing.T) {
	lim := New(5, time.Minute)
	for i := 0; i < 5; i++ {
		if !lim.Allow("192.168.1.1") {
			t.Fatalf("request %d should be allowed", i+1)
		}
	}
}

func TestRejectOverLimit(t *testing.T) {
	lim := New(3, time.Minute)
	for i := 0; i < 3; i++ {
		lim.Allow("10.0.0.1")
	}
	if lim.Allow("10.0.0.1") {
		t.Error("4th request should be rejected")
	}
}

func TestDifferentIPsIndependent(t *testing.T) {
	lim := New(2, time.Minute)
	lim.Allow("ip-a")
	lim.Allow("ip-a")
	if lim.Allow("ip-a") {
		t.Error("ip-a should be limited")
	}
	if !lim.Allow("ip-b") {
		t.Error("ip-b should be allowed (separate counter)")
	}
}

func TestWindowExpiry(t *testing.T) {
	lim := New(2, 50*time.Millisecond)
	lim.Allow("expiry")
	lim.Allow("expiry")
	if lim.Allow("expiry") {
		t.Error("should be limited")
	}
	time.Sleep(60 * time.Millisecond)
	if !lim.Allow("expiry") {
		t.Error("should be allowed after window expires")
	}
}

func TestRemainingCount(t *testing.T) {
	lim := New(5, time.Minute)
	if lim.Remaining("new-ip") != 5 {
		t.Errorf("expected 5 remaining, got %d", lim.Remaining("new-ip"))
	}
	lim.Allow("new-ip")
	lim.Allow("new-ip")
	if lim.Remaining("new-ip") != 3 {
		t.Errorf("expected 3 remaining, got %d", lim.Remaining("new-ip"))
	}
}

package ratelimit

import (
	"sync"
	"time"
)

type entry struct {
	timestamps []time.Time
}

type Limiter struct {
	mu     sync.Mutex
	max    int
	window time.Duration
	data   map[string]*entry
}

func New(max int, window time.Duration) *Limiter {
	return &Limiter{
		max:    max,
		window: window,
		data:   make(map[string]*entry),
	}
}

func (l *Limiter) Allow(ip string) bool {
	l.mu.Lock()
	defer l.mu.Unlock()

	now := time.Now()
	e, exists := l.data[ip]
	if !exists {
		e = &entry{}
		l.data[ip] = e
	}

	// Remove expired timestamps
	cutoff := now.Add(-l.window)
	valid := make([]time.Time, 0, len(e.timestamps))
	for _, ts := range e.timestamps {
		if ts.After(cutoff) {
			valid = append(valid, ts)
		}
	}
	e.timestamps = valid

	if len(e.timestamps) >= l.max {
		return false
	}

	e.timestamps = append(e.timestamps, now)
	return true
}

func (l *Limiter) Remaining(ip string) int {
	l.mu.Lock()
	defer l.mu.Unlock()

	e, exists := l.data[ip]
	if !exists {
		return l.max
	}

	now := time.Now()
	cutoff := now.Add(-l.window)
	count := 0
	for _, ts := range e.timestamps {
		if ts.After(cutoff) {
			count++
		}
	}

	remaining := l.max - count
	if remaining < 0 {
		return 0
	}
	return remaining
}
